import React from "react";
import styles from "./button-delete.module.css";
import { useDispatch } from "react-redux";
import { removeItem } from "../../app/cartSlice";
import { useTranslation } from "react-i18next";

interface ButtonDeleteProps {
  productId: number; 
}

const ButtonDelete: React.FC<ButtonDeleteProps> = ({ productId }) => {
  const [t] = useTranslation("global");

  const dispatch = useDispatch();

  const handleRemoveFromCart = () => {
    dispatch(removeItem(productId)); // Dispatch the removeItem action with the productId
  };

  return (
    <button
      type="button"
      className={styles.button_delete}
      onClick={handleRemoveFromCart}
    >
      {t("btn.delete")}
    </button>
  );
};

export default ButtonDelete;
